    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //    {
        //        "tag": 'semiannual',  // 'month', 'quarter', "perpetual", "semiannual",
        //        "pair": "ETH:USD",
        //        "symbol": "fi_ethusd_220624",
        //        "markPrice": "2925.72",
        //        "bid": "2923.8",
        //        "bidSize": "16804",
        //        "ask": "2928.65",
        //        "askSize": "1339",
        //        "vol24h": "860493",
        //        "openInterest": "3023363.00000000",
        //        "open24h": "3021.25",
        //        "indexPrice": "2893.71",
        //        "last": "2942.25",
        //        "lastTime": "2022-02-18T14:08:15.578Z",
        //        "lastSize": "151",
        //        "suspended": false
        //    }
        //
        //    {
        //        "symbol": "in_xbtusd", // "rr_xbtusd",
        //        "last": "40411",
        //        "lastTime": "2022-02-18T14:16:28.000Z"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.parse8601(this.safeString(ticker, "lastTime"));
        Object open = this.safeString(ticker, "open24h");
        Object last = this.safeString(ticker, "last");
        Object change = Precise.stringSub(last, open);
        Object percentage = Precise.stringMul(Precise.stringDiv(change, open), "100");
        Object average = Precise.stringDiv(Precise.stringAdd(open, last), "2");
        Object volume = this.safeString(ticker, "vol24h");
        Object baseVolume = null;
        Object quoteVolume = null;
        Object isIndex = this.safeBool(market, "index", false);
        if (!Helpers.isTrue(isIndex))
        {
            if (Helpers.isTrue(Helpers.GetValue(market, "linear")))
            {
                baseVolume = volume;
            } else if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
            {
                quoteVolume = volume;
            }
        }
        final Object finalBaseVolume = baseVolume;
        final Object finalQuoteVolume = quoteVolume;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", KrakenfuturesCore.this.iso8601(timestamp) );
            put( "high", null );
            put( "low", null );
            put( "bid", KrakenfuturesCore.this.safeString(ticker, "bid") );
            put( "bidVolume", KrakenfuturesCore.this.safeString(ticker, "bidSize") );
            put( "ask", KrakenfuturesCore.this.safeString(ticker, "ask") );
            put( "askVolume", KrakenfuturesCore.this.safeString(ticker, "askSize") );
            put( "vwap", null );
            put( "open", open );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", change );
            put( "percentage", percentage );
            put( "average", average );
            put( "baseVolume", finalBaseVolume );
            put( "quoteVolume", finalQuoteVolume );
            put( "markPrice", KrakenfuturesCore.this.safeString(ticker, "markPrice") );
            put( "indexPrice", KrakenfuturesCore.this.safeString(ticker, "indexPrice") );
            put( "info", ticker );
        }});
    }

    /**
     * @method
     * @name krakenfutures#fetchOHLCV
     * @see https://docs.kraken.com/api/docs/futures-api/charts/candles
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDeterministic("fetchOHLCV", symbol, since, limit, timeframe, parameters, 2000)).join();
            }
            final Object finalParameters = parameters;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "price_type", KrakenfuturesCore.this.safeString(finalParameters, "price", "trade") );
                put( "interval", KrakenfuturesCore.this.safeString(KrakenfuturesCore.this.timeframes, timeframe, timeframe) );
            }};
            parameters = this.omit(parameters, "price");
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Object duration = this.parseTimeframe(timeframe);
                Helpers.addElementToObject(request, "from", this.parseToInt(Helpers.divide(since, 1000)));
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = 2000;
                }
                limit = Helpers.mathMin(limit, 2000);
                Object toTimestamp = this.sum(Helpers.GetValue(request, "from"), Helpers.subtract(Helpers.multiply(limit, duration), 1));
                Object currentTimestamp = this.seconds();
                Helpers.addElementToObject(request, "to", Helpers.mathMin(toTimestamp, currentTimestamp));
            } else if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                limit = Helpers.mathMin(limit, 2000);
                Object duration = this.parseTimeframe(timeframe);
                Helpers.addElementToObject(request, "to", this.seconds());
                Helpers.addElementToObject(request, "from", this.parseToInt(Helpers.subtract(Helpers.GetValue(request, "to"), (Helpers.multiply(duration, limit)))));
            }
            Object response = (this.chartsGetPriceTypeSymbolInterval(this.extend(request, parameters))).join();
            //
            //    {
            //        "candles": [
            //            {
            //                "time": 1645198500000,
            //                "open": "309.15000000000",
            //                "high": "309.15000000000",
            //                "low": "308.70000000000",
            //                "close": "308.85000000000",
            //                "volume": 0
            //            }
            //        ],
            //        "more_candles": true
            //    }
            //
            Object candles = this.safeList(response, "candles");
            return this.parseOHLCVs((java.util.List<Object>)(candles), market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //    {
        //        "time": 1645198500000,
        //        "open": "309.15000000000",
        //        "high": "309.15000000000",
        //        "low": "308.70000000000",
        //        "close": "308.85000000000",
        //        "volume": 0
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, "time"), this.safeNumber(ohlcv, "open"), this.safeNumber(ohlcv, "high"), this.safeNumber(ohlcv, "low"), this.safeNumber(ohlcv, "close"), this.safeNumber(ohlcv, "volume")));
    }

    /**
     * @method
     * @name krakenfutures#fetchTrades
     * @see https://docs.kraken.com/api/docs/futures-api/trading/get-history
     * @see https://docs.kraken.com/api/docs/futures-api/history/get-public-execution-events
     * @description Fetch a history of filled trades that this account has made
     * @param {string} symbol Unified CCXT market symbol
     * @param {int} [since] Timestamp in ms of earliest trade. Not used by krakenfutures except in combination with params.until
     * @param {int} [limit] Total number of trades, cannot exceed 100
     * @param {object} [params] Exchange specific params
     * @param {int} [params.until] Timestamp in ms of latest trade
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @param {string} [params.method] The method to use to fetch trades. Can be 'historyGetMarketSymbolExecutions' or 'publicGetHistory' default is 'historyGetMarketSymbolExecutions'
     * @returns An array of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchTrades", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDynamic("fetchTrades", symbol, since, limit, parameters)).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object method = null;
            var methodparametersVariable = this.handleOptionAndParams(parameters, "fetchTrades", "method", "historyGetMarketSymbolExecutions");
            method = ((java.util.List<Object>) methodparametersVariable).get(0);
            parameters = ((java.util.List<Object>) methodparametersVariable).get(1);
            Object rawTrades = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object isFullHistoryEndpoint = (Helpers.isEqual(method, "historyGetMarketSymbolExecutions"));
            if (Helpers.isTrue(isFullHistoryEndpoint))
            {
                var requestparametersVariable = this.handleUntilOption("before", request, parameters);
                request = ((java.util.List<Object>) requestparametersVariable).get(0);
                parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    Helpers.addElementToObject(request, "since", since);
                    Helpers.addElementToObject(request, "sort", "asc");
                }
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Helpers.addElementToObject(request, "count", limit);
                }
                Object response = (this.historyGetMarketSymbolExecutions(this.extend(request, parameters))).join();
                //
                //    {
                //        "elements": [
                //            {
                //                "uid": "a5105030-f054-44cc-98ab-30d5cae96bef",
                //                "timestamp": "1710150778607",
                //                "event": {
                //                    "Execution": {
                //                        "execution": {
                //                            "uid": "2d485b71-cd28-4a1e-9364-371a127550d2",
                //                            "makerOrder": {
                //                                "uid": "0a25f66b-1109-49ec-93a3-d17bf9e9137e",
                //                                "tradeable": "PF_XBTUSD",
                //                                "direction": "Buy",
                //                                "quantity": "0.26500",
                //                                "timestamp": "1710150778570",
                //                                "limitPrice": "71907",
                //                                "orderType": "Post",
                //                                "reduceOnly": false,
                //                                "lastUpdateTimestamp": "1710150778570"
                //                            },
                //                            "takerOrder": {
                //                                "uid": "04de3ee0-9125-4960-bf8f-f63b577b6790",
                //                                "tradeable": "PF_XBTUSD",
                //                                "direction": "Sell",
                //                                "quantity": "0.0002",
                //                                "timestamp": "1710150778607",
                //                                "limitPrice": "71187.00",
                //                                "orderType": "Market",
                //                                "reduceOnly": false,
                //                                "lastUpdateTimestamp": "1710150778607"
                //                            },
                //                            "timestamp": "1710150778607",
                //                            "quantity": "0.0002",
                //                            "price": "71907",
                //                            "markPrice": "71903.32715463147",
                //                            "limitFilled": false,
                //                            "usdValue": "14.38"
                //                        },
                //                        "takerReducedQuantity": ""
                //                    }
                //                }
                //            },
                //            ... followed by older items
                //        ],
                //        "len": "1000",
                //        "continuationToken": "QTexMDE0OTe33NTcyXy8xNDIzAjc1NjY5MwI="
                //    }
                //
                Object elements = this.safeList(response, "elements", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                // we need to reverse the list to fix chronology
                rawTrades = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                Object length = Helpers.getArrayLength(elements);
                for (var i = 0; Helpers.isLessThan(i, length); i++)
                {
                    Object index = Helpers.subtract(Helpers.subtract(length, 1), i);
                    Object element = Helpers.GetValue(elements, index);
                    Object eventVar = this.safeDict(element, "event", new java.util.HashMap<String, Object>() {{}});
                    Object executionContainer = this.safeDict(eventVar, "Execution", new java.util.HashMap<String, Object>() {{}});
                    Object rawTrade = this.safeDict(executionContainer, "execution", new java.util.HashMap<String, Object>() {{}});
                    ((java.util.List<Object>)rawTrades).add(rawTrade);
                }
            } else
            {
                var requestparametersVariable = this.handleUntilOption("lastTime", request, parameters);
                request = ((java.util.List<Object>) requestparametersVariable).get(0);
                parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
                Object response = (this.publicGetHistory(this.extend(request, parameters))).join();
                //
                //    {
                //        "result": "success",
                //        "history": [
                //            {
                //                "time": "2022-03-18T04:55:37.692Z",
                //                "trade_id": 100,
                //                "price": 0.7921,
                //                "size": 1068,
                //                "side": "sell",
                //                "type": "fill",
                //                "uid": "6c5da0b0-f1a8-483f-921f-466eb0388265"
                //            },
                //            ...
                //        ],
                //        "serverTime": "2022-03-18T06:39:18.056Z"
                //    }
                //
                rawTrades = this.safeList(response, "history", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            }
            return this.parseTrades(rawTrades, market, since, limit);
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (recent trades)
        //
        //    {
        //        "time": "2019-02-14T09:25:33.920Z",
        //        "trade_id": 100,
        //        "price": 3574,
        //        "size": 100,
        //        "side": "buy",
        //        "type": "fill" // fill, liquidation, assignment, termination
        //        "uid": "11c3d82c-9e70-4fe9-8115-f643f1b162d4"
        //    }
        //
        // fetchTrades (executions history)
        //
        //    {
        //        "timestamp": "1710152516830",
        //        "price": "71927.0",
        //        "quantity": "0.0695",
        //        "markPrice": "71936.38701675525",
        //        "limitFilled": true,
        //        "usdValue": "4998.93",
        //        "uid": "116ae634-253f-470b-bd20-fa9d429fb8b1",
        //        "makerOrder": { "uid": "17bfe4de-c01e-4938-926c-617d2a2d0597", "tradeable": "PF_XBTUSD", "direction": "Buy", "quantity": "0.0695", "timestamp": "1710152515836", "limitPrice": "71927.0", "orderType": "Post", "reduceOnly": false, "lastUpdateTimestamp": "1710152515836" },
        //        "takerOrder": { "uid": "d3e437b4-aa70-4108-b5cf-b1eecb9845b5", "tradeable": "PF_XBTUSD", "direction": "Sell", "quantity": "0.940100", "timestamp": "1710152516830", "limitPrice": "71915", "orderType": "IoC", "reduceOnly": false, "lastUpdateTimestamp": "1710152516830" }
        //    }
        //
        // fetchMyTrades (private)
        //
        //    {
        //        "fillTime": "2016-02-25T09:47:01.000Z",
        //        "order_id": "c18f0c17-9971-40e6-8e5b-10df05d422f0",
        //        "fill_id": "522d4e08-96e7-4b44-9694-bfaea8fe215e",
        //        "cliOrdId": "d427f920-ec55-4c18-ba95-5fe241513b30",     // OPTIONAL
        //        "symbol": "fi_xbtusd_180615",
        //        "side": "buy",
        //        "size": 2000,
        //        "price": 4255,
        //        "fillType": "maker"                                     // taker, takerAfterEdit, maker, liquidation, assignee
        //    }
        //
        // execution report (createOrder, editOrder)
        //
        //    {
        //        "executionId": "e1ec9f63-2338-4c44-b40a-43486c6732d7",
        //        "price": 7244.5,
        //        "amount": 10,
        //        "orderPriorEdit": null,
        //        "orderPriorExecution": {
        //            "orderId": "61ca5732-3478-42fe-8362-abbfd9465294",
        //            "cliOrdId": null,
        //            "type": "lmt",
        //            "symbol": "pi_xbtusd",
        //            "side": "buy",
        //            "quantity": 10,
        //            "filled": 0,
        //            "limitPrice": 7500,
        //            "reduceOnly": false,
        //            "timestamp": "2019-12-11T17:17:33.888Z",
        //            "lastUpdateTimestamp": "2019-12-11T17:17:33.888Z"
        //        },
        //        "takerReducedQuantity": null,
        //        "type": "EXECUTION"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString2(trade, "time", "fillTime"));
        Object price = this.safeString(trade, "price");
        Object amount = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("size", "amount", "quantity")), "0.0");
        Object id = this.safeString2(trade, "uid", "fill_id");
        if (Helpers.isTrue(Helpers.isEqual(id, null)))
        {
            id = this.safeString(trade, "executionId");
        }
        Object order = this.safeString(trade, "order_id");
        Object marketId = this.safeString(trade, "symbol");
        Object side = this.safeString(trade, "side");
        Object type = null;
        Object priorEdit = this.safeValue(trade, "orderPriorEdit");
        Object priorExecution = this.safeValue(trade, "orderPriorExecution");
        if (Helpers.isTrue(!Helpers.isEqual(priorExecution, null)))
        {
            order = this.safeString(priorExecution, "orderId");
            marketId = this.safeString(priorExecution, "symbol");
            side = this.safeString(priorExecution, "side");
            type = this.safeString(priorExecution, "type");
        } else if (Helpers.isTrue(!Helpers.isEqual(priorEdit, null)))
        {
            order = this.safeString(priorEdit, "orderId");
            marketId = this.safeString(priorEdit, "symbol");
            side = this.safeString(priorEdit, "type");
            type = this.safeString(priorEdit, "type");
        }
        if (Helpers.isTrue(!Helpers.isEqual(type, null)))
        {
            type = this.parseOrderType(type);
        }
        market = this.safeMarket(marketId, market);
        Object cost = null;
        Object linear = this.safeBool(market, "linear");
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(amount, null))) && Helpers.isTrue((!Helpers.isEqual(price, null)))) && Helpers.isTrue((!Helpers.isEqual(market, null)))))
        {
            if (Helpers.isTrue(linear))
            {
                cost = Precise.stringMul(amount, price); // in quote
            } else
            {
                cost = Precise.stringDiv(amount, price); // in base
            }
            Object contractSize = this.safeString(market, "contractSize");
            cost = Precise.stringMul(cost, contractSize);
        }
        Object takerOrMaker = null;
        Object fillType = this.safeString(trade, "fillType");
        if (Helpers.isTrue(!Helpers.isEqual(fillType, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(fillType, "taker"), 0)))
            {
                takerOrMaker = "taker";
            } else if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(fillType, "maker"), 0)))
            {
                takerOrMaker = "maker";
            }
        }
        Object isHistoricalExecution = (Helpers.inOp(trade, "takerOrder"));
        if (Helpers.isTrue(isHistoricalExecution))
        {
            timestamp = this.safeInteger(trade, "timestamp");
            Object taker = this.safeDict(trade, "takerOrder", new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(!Helpers.isEqual(taker, null)))
            {
                side = this.safeStringLower(taker, "direction");
                takerOrMaker = "taker";
            }
        }
        Object fee = null;
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(takerOrMaker, null))) && Helpers.isTrue((!Helpers.isEqual(cost, null)))))
        {
            Object feeRate = this.safeString(market, takerOrMaker);
            final Object finalCost = cost;
            final Object finalMarket = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", Precise.stringMul(finalCost, feeRate) );
                put( "currency", KrakenfuturesCore.this.safeString(finalMarket, "quote") );
                put( "rate", feeRate );
            }};
        }
        final Object finalId = id;
        final Object finalMarket_2 = market;
        final Object finalTimestamp = timestamp;
        final Object finalOrder = order;
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalPrice = price;
        final Object finalAmount = amount;
        final Object finalCost_2 = cost;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", finalId );
            put( "symbol", KrakenfuturesCore.this.safeString(finalMarket_2, "symbol") );
            put( "timestamp", finalTimestamp );
            put( "datetime", KrakenfuturesCore.this.iso8601(finalTimestamp) );
            put( "order", finalOrder );
            put( "type", finalType );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", finalPrice );
            put( "amount", ((Helpers.isTrue(linear))) ? finalAmount : null );
            put( "cost", finalCost_2 );
            put( "fee", finalFee );
        }});
    }

    public Object createOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object market = this.market(symbol);
        symbol = Helpers.GetValue(market, "symbol");
        type = this.safeString(parameters, "orderType", type);
        Object timeInForce = this.safeString(parameters, "timeInForce");
        Object postOnly = false;
        var postOnlyparametersVariable = this.handlePostOnly(Helpers.isEqual(type, "market"), Helpers.isEqual(type, "post"), parameters);
        postOnly = ((java.util.List<Object>) postOnlyparametersVariable).get(0);
        parameters = ((java.util.List<Object>) postOnlyparametersVariable).get(1);
        if (Helpers.isTrue(postOnly))
        {
            type = "post";
        } else if (Helpers.isTrue(Helpers.isEqual(timeInForce, "ioc")))
        {
            type = "ioc";
        } else if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
        {
            type = "lmt";
        } else if (Helpers.isTrue(Helpers.isEqual(type, "market")))
        {
            type = "mkt";
        }
        final Object finalSymbol = symbol;
        Object request = new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(market, "id") );
            put( "side", side );
            put( "size", KrakenfuturesCore.this.amountToPrecision(finalSymbol, amount) );
        }};
        Object clientOrderId = this.safeString2(parameters, "clientOrderId", "cliOrdId");
        if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
        {
            Helpers.addElementToObject(request, "cliOrdId", clientOrderId);
        }
        Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stopPrice");
        Object isTriggerOrder = !Helpers.isEqual(triggerPrice, null);
        Object stopLossTriggerPrice = this.safeString(parameters, "stopLossPrice");
        Object takeProfitTriggerPrice = this.safeString(parameters, "takeProfitPrice");
        Object isStopLossTriggerOrder = !Helpers.isEqual(stopLossTriggerPrice, null);
        Object isTakeProfitTriggerOrder = !Helpers.isEqual(takeProfitTriggerPrice, null);
        Object isStopLossOrTakeProfitTrigger = Helpers.isTrue(isStopLossTriggerOrder) || Helpers.isTrue(isTakeProfitTriggerOrder);
        Object triggerSignal = this.safeString(parameters, "triggerSignal", "last");
        Object reduceOnly = this.safeValue(parameters, "reduceOnly");
        if (Helpers.isTrue(Helpers.isTrue(isStopLossOrTakeProfitTrigger) || Helpers.isTrue(isTriggerOrder)))
        {
            Helpers.addElementToObject(request, "triggerSignal", triggerSignal);
        }
        if (Helpers.isTrue(isTriggerOrder))
        {
            type = "stp";
            Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, triggerPrice));
        } else if (Helpers.isTrue(isStopLossOrTakeProfitTrigger))
        {
            reduceOnly = true;
            if (Helpers.isTrue(isStopLossTriggerOrder))
            {
                type = "stp";
                Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, stopLossTriggerPrice));
            } else if (Helpers.isTrue(isTakeProfitTriggerOrder))
            {
                type = "take_profit";
                Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, takeProfitTriggerPrice));
            }
        }
        if (Helpers.isTrue(reduceOnly))
        {
            Helpers.addElementToObject(request, "reduceOnly", true);
        }
        Helpers.addElementToObject(request, "orderType", type);
        if (Helpers.isTrue(!Helpers.isEqual(price, null)))
        {
            Helpers.addElementToObject(request, "limitPrice", this.priceToPrecision(symbol, price));
        }
        parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId", "timeInForce", "triggerPrice", "stopLossPrice", "takeProfitPrice")));
        return this.extend(request, parameters);
    }

