    public Object parseMarketLeverageTiers(Object info, Object... optionalArgs)
    {
        /**
        * @method
        * @ignore
        * @param info Exchange market response for 1 market
        * @param market CCXT market
        */
        //
        //    {
        //        "symbol": "fi_ethusd_180928",
        //        "type": "futures_inverse",  // futures_vanilla  // spot index
        //        "underlying": "rr_ethusd",
        //        "lastTradingTime": "2018-09-28T15:00:00.000Z",
        //        "tickSize": 0.1,
        //        "contractSize": 1,
        //        "tradeable": true,
        //        "marginLevels": [
        //            {
        //                "contracts":0,
        //                "initialMargin":0.02,
        //                "maintenanceMargin":0.01
        //            },
        //            {
        //                "contracts":250000,
        //                "initialMargin":0.04,
        //                "maintenanceMargin":0.02
        //            },
        //            ...
        //        ],
        //        "isin": "GB00JVMLMP88",
        //        "retailMarginLevels": [
        //            {
        //                "contracts": 0,
        //                "initialMargin": 0.5,
        //                "maintenanceMargin": 0.25
        //            }
        //        ],
        //        "tags": [],
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marginLevels = this.safeValue(info, "marginLevels");
        Object marketId = this.safeString(info, "symbol");
        market = this.safeMarket(marketId, market);
        Object tiers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(Helpers.isEqual(marginLevels, null)))
        {
            return tiers;
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marginLevels)); i++)
        {
            Object tier = Helpers.GetValue(marginLevels, i);
            Object initialMargin = this.safeString(tier, "initialMargin");
            Object minNotional = this.safeNumber2(tier, "numNonContractUnits", "contracts");
            if (Helpers.isTrue(!Helpers.isEqual(i, 0)))
            {
                Object tiersLength = Helpers.getArrayLength(tiers);
                Object previousTier = Helpers.GetValue(tiers, Helpers.subtract(tiersLength, 1));
                Helpers.addElementToObject(previousTier, "maxNotional", minNotional);
            }
final Object finalI = i;
            final Object finalMarket = market;
                        ((java.util.List<Object>)tiers).add(new java.util.HashMap<String, Object>() {{
                put( "tier", KrakenfuturesCore.this.sum(finalI, 1) );
                put( "symbol", KrakenfuturesCore.this.safeSymbol(marketId, finalMarket) );
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
                put( "minNotional", minNotional );
                put( "maxNotional", null );
                put( "maintenanceMarginRate", KrakenfuturesCore.this.safeNumber(tier, "maintenanceMargin") );
                put( "maxLeverage", KrakenfuturesCore.this.parseNumber(Precise.stringDiv("1", initialMargin)) );
                put( "info", tier );
            }});
        }
        return tiers;
    }

    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        // transfer
        //
        //    {
        //        "result": "success",
        //        "serverTime": "2022-04-12T01:22:53.420Z"
        //    }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object datetime = this.safeString(transfer, "serverTime");
        return new java.util.HashMap<String, Object>() {{
            put( "info", transfer );
            put( "id", null );
            put( "timestamp", KrakenfuturesCore.this.parse8601(datetime) );
            put( "datetime", datetime );
            put( "currency", KrakenfuturesCore.this.safeString(currency, "code") );
            put( "amount", null );
            put( "fromAccount", null );
            put( "toAccount", null );
            put( "status", KrakenfuturesCore.this.safeString(transfer, "result") );
        }};
    }

    public Object parseAccount(Object account)
    {
        Object accountByType = new java.util.HashMap<String, Object>() {{
            put( "main", "cash" );
            put( "funding", "cash" );
            put( "future", "cash" );
            put( "futures", "cash" );
            put( "cashAccount", "cash" );
            put( "multiCollateralMarginAccount", "flex" );
            put( "multiCollateral", "flex" );
            put( "multiCollateralMargin", "flex" );
        }};
        if (Helpers.isTrue(Helpers.inOp(accountByType, account)))
        {
            return Helpers.GetValue(accountByType, account);
        } else if (Helpers.isTrue(Helpers.inOp(this.markets, account)))
        {
            Object market = this.market(account);
            Object marketId = Helpers.GetValue(market, "id");
            Object splitId = Helpers.split(((String)marketId), "_");
            if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
            {
                return Helpers.add("fi_", this.safeString(splitId, 1));
            } else
            {
                return Helpers.add("fv_", this.safeString(splitId, 1));
            }
        } else
        {
            return account;
        }
    }

    /**
     * @method
     * @name krakenfutures#transferOut
     * @description transfer from futures wallet to spot wallet
     * @param {str} code Unified currency code
     * @param {float} amount Size of the transfer
     * @param {dict} [params] Exchange specific parameters
     * @returns a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transferOut(Object code, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            return (this.transfer(code, amount, "future", "spot", parameters)).join();
        });

    }

    /**
     * @method
     * @name krakenfutures#transfer
     * @see https://docs.kraken.com/api/docs/futures-api/trading/transfer
     * @see https://docs.kraken.com/api/docs/futures-api/trading/sub-account-transfer
     * @description transfers currencies between sub-accounts
     * @param {string} code Unified currency code
     * @param {float} amount Size of the transfer
     * @param {string} fromAccount 'main'/'funding'/'future', 'flex', or a unified market symbol
     * @param {string} toAccount 'main'/'funding', 'flex', 'spot' or a unified market symbol
     * @param {object} [params] Exchange specific parameters
     * @returns a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount2, Object toAccount2, Object... optionalArgs)
    {
        final Object fromAccount3 = fromAccount2;
        final Object toAccount3 = toAccount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object fromAccount = fromAccount3;
            Object toAccount = toAccount3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            if (Helpers.isTrue(Helpers.isEqual(fromAccount, "spot")))
            {
                throw new BadRequest((String)Helpers.add(this.id, " transfer does not yet support transfers from spot")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "amount", amount );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(toAccount, "spot")))
            {
                if (Helpers.isTrue(!Helpers.isEqual(this.parseAccount(fromAccount), "cash")))
                {
                    throw new BadRequest((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " transfer cannot transfer from "), fromAccount), " to "), toAccount)) ;
                }
                Helpers.addElementToObject(request, "currency", Helpers.GetValue(currency, "id"));
                response = (this.privatePostWithdrawal(this.extend(request, parameters))).join();
            } else
            {
                Helpers.addElementToObject(request, "fromAccount", this.parseAccount(fromAccount));
                Helpers.addElementToObject(request, "toAccount", this.parseAccount(toAccount));
                Helpers.addElementToObject(request, "unit", Helpers.GetValue(currency, "id"));
                response = (this.privatePostTransfer(this.extend(request, parameters))).join();
            }
            //
            //    {
            //        "result": "success",
            //        "serverTime": "2022-04-12T01:22:53.420Z"
            //    }
            //
            Object transfer = this.parseTransfer(response, currency);
            final Object finalFromAccount = fromAccount;
            final Object finalToAccount = toAccount;
            return this.extend(transfer, new java.util.HashMap<String, Object>() {{
                put( "amount", amount );
                put( "fromAccount", finalFromAccount );
                put( "toAccount", finalToAccount );
            }});
        });

    }

